<?php declare(strict_types=1); namespace App\Models; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\HasMany; final class BtaqSession extends Model{protected $fillable=['btaq_group_id','btaq_schedule_id','academic_year_id','semester_id','teacher_employee_id','session_date','scheduled_start_time','scheduled_end_time','actual_start_time','actual_end_time','meeting_number','btaq_material_id','topic','learning_target','learning_activity','learning_method','evaluation','obstacles','follow_up','teacher_notes','status','submitted_at','finalized_by','finalized_at','verified_by','verified_at','verification_notes','rejected_by','rejected_at','rejection_reason','created_by','updated_by']; protected function casts():array{return ['session_date'=>'date','submitted_at'=>'datetime','finalized_at'=>'datetime','verified_at'=>'datetime','rejected_at'=>'datetime'];} public function group():BelongsTo{return $this->belongsTo(BtaqGroup::class,'btaq_group_id');} public function schedule():BelongsTo{return $this->belongsTo(BtaqSchedule::class,'btaq_schedule_id');} public function teacher():BelongsTo{return $this->belongsTo(Employee::class,'teacher_employee_id');} public function attendances():HasMany{return $this->hasMany(BtaqSessionAttendance::class);} public function progresses():HasMany{return $this->hasMany(BtaqStudentProgress::class);}}
